   650	    }
   651	
   652	    fn execute(self) -> Result<std::process::Output, Error> {
   653	        let output_file =
   654	            tempfile::NamedTempFile::new().map_err(|_| Error::ProviderCommandUnavailable)?;
   655	        let output_path = output_file.path().to_path_buf();
   656	        let stdout = output_file
   657	            .reopen()
   658	            .map_err(|_| Error::ProviderCommandUnavailable)?;
   659	        let mut child = Command::new(self.session_launcher)
   660	            .arg(self.command)
   661	            .args(&self.arguments)
   662	            .stdout(Stdio::from(stdout))
   663	            .stderr(Stdio::null())
   664	            .spawn()
   665	            .map_err(|_| Error::ProviderCommandUnavailable)?;
   666	        let deadline = Instant::now() + self.timeout.duration();
   667	        loop {
   668	            if let Some(status) = child
   669	                .try_wait()
   670	                .map_err(|_| Error::ProviderCommandUnavailable)?
   671	            {
   672	                let output =
   673	                    std::fs::read(&output_path).map_err(|_| Error::ProviderCommandUnavailable)?;
   674	                return Ok(std::process::Output {
   675	                    status,
   676	                    stdout: output,
   677	                    stderr: Vec::new(),
   678	                });
   679	            }
   680	            if Instant::now() >= deadline {
   681	                self.terminate_process_group(&mut child)?;
   682	                return Err(Error::ProviderCommandTimedOut);
   683	            }
   684	            thread::sleep(Duration::from_millis(10));
   685	        }
   686	    }
   687	
   688	    fn terminate_process_group(&self, child: &mut std::process::Child) -> Result<(), Error> {
   689	        let process_group = Pid::from_raw(-(child.id() as i32));
   690	        kill(process_group, Signal::SIGTERM)
   691	            .map_err(|_| Error::ProviderProcessGroupTeardownFailed)?;
   692	        self.wait_for_term_grace(child)?;
   693	        if self.process_group_has_members(process_group)? {
   694	            kill(process_group, Signal::SIGKILL)
   695	                .map_err(|_| Error::ProviderProcessGroupTeardownFailed)?;
   696	            self.wait_for_process_group_exit(process_group)?;
   697	        }
   698	        child
   699	            .wait()
   700	            .map_err(|_| Error::ProviderProcessGroupTeardownFailed)?;
   701	        Ok(())
   702	    }
   703	
   704	    fn wait_for_term_grace(&self, child: &mut std::process::Child) -> Result<(), Error> {
   705	        let grace_deadline = Instant::now() + Duration::from_millis(100);
   706	        while Instant::now() < grace_deadline {
   707	            let _ = child
   708	                .try_wait()
   709	                .map_err(|_| Error::ProviderProcessGroupTeardownFailed)?;
   710	            thread::sleep(Duration::from_millis(10));
   711	        }
   712	        Ok(())
   713	    }
   714	
   715	    fn process_group_has_members(&self, process_group: Pid) -> Result<bool, Error> {
   716	        match kill(process_group, None) {
   717	            Ok(()) => Ok(true),
   718	            Err(Errno::ESRCH) => Ok(false),
   719	            Err(_) => Err(Error::ProviderProcessGroupTeardownFailed),
   720	        }
   721	    }
   722	
   723	    fn wait_for_process_group_exit(&self, process_group: Pid) -> Result<(), Error> {
   724	        let teardown_deadline = Instant::now() + Duration::from_millis(100);
   725	        while Instant::now() < teardown_deadline {
   726	            if !self.process_group_has_members(process_group)? {
   727	                return Ok(());
   728	            }
   729	            thread::sleep(Duration::from_millis(10));
   730	        }
   731	        if self.process_group_has_members(process_group)? {
   732	            return Err(Error::ProviderProcessGroupTeardownFailed);
   733	        }
   734	        Ok(())
   735	    }
   736	}
