   146	        let configuration_root =
   147	            SpiritJudgeConfigurationPath::from_environment_or(self.config_root.clone())
   148	                .map_err(|error| error.to_string())?;
   149	        let provider_name = ProviderName::unchecked(self.provider.provider_name());
   150	        let authorization = self.resolved_authorization()?;
   151	        self.validate_provider_authorization(&authorization)?;
   152	        let client = self.provider_client()?;
   153	        let adapter = SpiritJudgeAdapter::new(
   154	            SpiritJudgeAdapterConfiguration::new(
   155	                configuration_root,
   156	                provider_name,
   157	                ProviderModelName::unchecked(self.model),
   158	                self.reasoning_effort,
   159	                authorization,
   160	            ),
   161	            client,
   162	        );
   163	        SpiritJudgeSocketServer::new(SpiritJudgeSocketPath::new(self.socket), adapter)
   164	            .serve()
   165	            .await
   166	            .map_err(|error| error.to_string())
   167	    }
   168	
   169	    fn resolved_authorization(&self) -> Result<ResolvedProviderAuthorization, String> {
   170	        let authorization = match (
   171	            &self.bearer_secret_source,
   172	            &self.external_authorization_source,
   173	        ) {
   174	            (Some(_), Some(_)) => {
   175	                return Err(
   176	                    "judge provider cannot combine bearer and external authorization".to_owned(),
   177	                );
   178	            }
   179	            (Some(reference), None) => ProviderAuthorization::bearer_secret_source(
   180	                SecretSourceReference::new(reference).map_err(|error| error.to_string())?,
   181	            ),
   182	            (None, Some(reference)) => ProviderAuthorization::external_session(
   183	                SessionAuthorizationSourceReference::new(reference)
   184	                    .map_err(|error| error.to_string())?,
   185	            ),
   186	            (None, None) => ProviderAuthorization::no_secret(),
   187	        };
   188	        authorization
   189	            .resolve(&EnvironmentSecretResolver)
   190	            .map_err(|error| error.to_string())
   191	    }
   192	
   193	    fn validate_provider_authorization(
   194	        &self,
   195	        authorization: &ResolvedProviderAuthorization,
   196	    ) -> Result<(), String> {
   197	        if self.provider != ProviderSelection::OpenAiCodex {
   198	            return Ok(());
   199	        }
   200	        let ResolvedProviderAuthorization::ExternalSession(reference) = authorization else {
   201	            return Err(
   202	                "OpenAI Codex requires the codex-login external session reference".to_owned(),
   203	            );
   204	        };
   205	        if reference.as_str() != "codex-login" {
   206	            return Err("OpenAI Codex external session reference is unsupported".to_owned());
   207	        }
   208	        Ok(())
   209	    }
   210	
   211	    fn provider_client(&self) -> Result<Box<dyn ProviderClient>, String> {
   212	        match self.provider {
   213	            ProviderSelection::Fixture => Ok(Box::new(FixtureProviderClient::from_text(
   214	                self.fixture_output
   215	                    .clone()
   216	                    .unwrap_or_else(|| "Accept".to_owned()),
   217	            ))),
   218	            ProviderSelection::OpenAiCompatible => self.openai_compatible_client(),
   219	            ProviderSelection::OpenAiCodex => self.openai_codex_client(),
   220	        }
   221	    }
   222	
   223	    fn openai_codex_client(&self) -> Result<Box<dyn ProviderClient>, String> {
   224	        let session_launcher = self
   225	            .session_launcher
   226	            .clone()
   227	            .unwrap_or_else(|| PathBuf::from("setsid"));
   228	        let command = self
   229	            .codex_command
   230	            .clone()
   231	            .unwrap_or_else(|| PathBuf::from("codex"));
   232	        let timeout = ProviderCallTimeout::from_milliseconds(self.provider_timeout_milliseconds)
   233	            .map_err(|error| error.to_string())?;
   234	        Ok(Box::new(OpenAiCodexProviderClient::new(
   235	            session_launcher,
   236	            command,
   237	            timeout,
   238	        )))
   239	    }
   240	
   241	    #[cfg(feature = "live-provider")]
   242	    fn openai_compatible_client(&self) -> Result<Box<dyn ProviderClient>, String> {
   243	        let endpoint = self.endpoint.clone().ok_or_else(|| {
   244	            "openai-compatible provider requires --endpoint or SPIRIT_JUDGE_PROVIDER_ENDPOINT"
   245	                .to_owned()
   246	        })?;
   247	        Ok(Box::new(OpenAiCompatibleProviderClient::new(
   248	            EndpointUrl::new(endpoint).map_err(|error| error.to_string())?,
   249	        )))
   250	    }
   251	
   252	    #[cfg(not(feature = "live-provider"))]
   253	    fn openai_compatible_client(&self) -> Result<Box<dyn ProviderClient>, String> {
   254	        let _endpoint = &self.endpoint;
   255	        Err("openai-compatible provider requires the live-provider feature".to_owned())
   256	    }
   257	
   258	    fn usage() -> String {
   259	        "usage: spirit-judge serve --socket <path> [--config-root <path>] [--provider fixture|openai-compatible|openai-codex] [--endpoint <url>] [--model <name>] [--reasoning-effort low|medium|high] [--provider-timeout-milliseconds positive-integer] [--bearer-secret-source env:NAME] [--external-authorization-source codex-login] [--session-launcher <path>] [--codex-command <path>] [--fixture-output <nota>]".to_owned()
   260	    }
   261	
   262	    fn reasoning_effort_from_name(name: &str) -> Result<ReasoningEffort, String> {
   263	        match name {
   264	            "low" => Ok(ReasoningEffort::Low),
   265	            "medium" => Ok(ReasoningEffort::Medium),
   266	            "high" => Ok(ReasoningEffort::High),
   267	            _ => Err(Self::usage()),
   268	        }
   269	    }
   270	}
   271	
   272	impl ProviderSelection {
   273	    fn from_name(name: &str) -> Result<Self, String> {
   274	        match name {
   275	            "fixture" => Ok(Self::Fixture),
   276	            "openai-compatible" => Ok(Self::OpenAiCompatible),
   277	            "openai-codex" => Ok(Self::OpenAiCodex),
   278	            _ => Err(SpiritJudgeCommand::usage()),
   279	        }
   280	    }
   281	
   282	    fn provider_name(&self) -> &'static str {
   283	        match self {
   284	            Self::Fixture => "fixture",
   285	            Self::OpenAiCompatible => "openai-compatible",
   286	            Self::OpenAiCodex => "openai-codex",
   287	        }
   288	    }
   289	}

README
     1	# spirit-judge
     2	
     3	Spirit judge edge adapter executable and library.
     4	
     5	`spirit-judge` consumes `signal-spirit-judge`, reads prompt/config data from a
     6	configured `spirit-judge-config` checkout or package path, and calls model
     7	providers through `judge`. It does not depend on the Spirit daemon and is not
     8	Spirit storage.
     9	
    10	The `openai-codex` provider accepts only the `codex-login` external-session
    11	reference, verifies that the configured Codex executable reports an authenticated
    12	ambient session, and never copies a bearer token into Nix, unit definitions, or
    13	the Spirit wire contract. The reference does not select an account; production
    14	must remain stopped when that ambient account cannot be independently bounded.
    15	Each Codex child has a typed deadline and failure result. `--reasoning-effort`
    16	selects the typed Low, Medium, or High provider setting.

ARCH
     1	# spirit-judge — architecture
     2	
     3	`spirit-judge` is the Spirit-specific text/model edge adapter for model-backed
     4	Spirit admission and referent-registration judgment.
     5	
     6	It sits between the typed `signal-spirit-judge` request/reply contract and the
     7	provider-facing mechanics in `judge`. It reads prompt/config data from an
     8	external `spirit-judge-config` checkout or package path at runtime, lowers typed
     9	Spirit judge packets into provider prompts, parses model NOTA verdict replies
    10	back into typed Spirit judge replies, and serves the exchange over a Unix socket.
    11	
    12	## Boundary
    13	
    14	Owned here:
    15	
    16	- adapter configuration records and prompt/config path selection;
    17	- request lowering from `signal-spirit-judge` into provider calls through
    18	  `judge`;
    19	- model NOTA reply parsing back into `signal-spirit-judge` replies;
    20	- privacy-safe diagnostics that prefer redaction and hashes;
    21	- local adapter process and Unix socket framing.
    22	
    23	Not owned here:
    24	
    25	- provider-generic mechanics, retries, proxy protocol, and secret-source
    26	  resolution, which belong in `judge`;
    27	- Spirit storage, admission, and referent namespace mutation, which belong in
    28	  `spirit`;
    29	- prompt prose and fixtures, which belong in `spirit-judge-config`;
    30	- generic judgment schemas or generic judge-anything adapters.
    31	
    32	## Privacy and admission bias
    33	
    34	Requests carry explicit public/private judgment scope. The adapter may send the
    35	request text to the configured provider only at this boundary. Diagnostics must
    36	not expose raw private request text or raw provider output by default; private
    37	model explanations are replaced with a redaction marker plus a content hash.
    38	
    39	Parser failures, malformed model replies, provider failures, and unavailable
    40	configuration fail closed as typed request rejections rather than accidental
    41	admissions.

