     2	  config,
     3	  inputs,
     4	  lib,
     5	  pkgs,
     6	  horizon,
     7	  user,
     8	  ...
     9	}:
    10	let
    11	  inherit (lib)
    12	    mkIf
    13	    mkOption
    14	    ;
    15	  inherit (lib.types) bool;
    16	  inherit (user) size;
    17	
    18	  system = pkgs.stdenv.hostPlatform.system;
    19	  agentPackage = inputs.agent.packages.${system}.default;
    20	  spiritPackage = inputs.spirit.packages.${system}.default;
    21	  spiritJudgePackage = inputs.spirit-judge.packages.${system}.default;
    22	  spiritJudgeConfig = inputs.spirit-judge-config;
    23	  codexCliPackage = inputs.codex-cli.packages.${system}.default;
    24	
    25	  # These values configure the retained agent daemon only. Spirit judgment is
    26	  # served by the separate OpenAI Codex adapter below.
    27	  providerName = "deepseek";
    28	  defaultModel = "deepseek-v4-flash";
    29	  providerEndpoint = "https://api.deepseek.com/v1";
    30	  providerGopassPath = "platform.deepseek.com/api-key";
    31	
    32	  # The agent daemon resolves its own provider credential at runtime. No secret
    33	  # value is embedded in this Nix configuration.
    34	  agentServicePath = lib.concatStringsSep ":" [
    35	    "${config.home.homeDirectory}/.nix-profile/bin"
    36	    "/run/current-system/sw/bin"
    37	    "/run/wrappers/bin"
    38	  ];
    39	
    40	  stateDirectory = "${config.home.homeDirectory}/.local/state/spirit";
    41	  socketPath = "${stateDirectory}/spirit.sock";
    42	  metaSocketPath = "${stateDirectory}/meta-spirit.sock";
    43	  spiritJudgeSocketPath = "${stateDirectory}/spirit-judge.sock";
    44	  databasePath = "${stateDirectory}/spirit.sema";
    45	  configurationPath = "spirit.config.rkyv";
    46	
    47	  agentStateDirectory = "${config.home.homeDirectory}/.local/state/agent";
    48	  agentSocketPath = "${agentStateDirectory}/agent.sock";
    49	  agentMetaSocketPath = "${agentStateDirectory}/agent-meta.sock";
    50	  agentDatabasePath = "${agentStateDirectory}/agent.sema";
    51	  agentConfigurationPath = "agent.config.rkyv";
    52	
    53	  agentDaemonConfiguration = pkgs.runCommand "agent-daemon-configuration" { } ''
    54	    set -eu
    55	
    56	    mkdir -p "$out"
    57	    ${agentPackage}/bin/agent-write-configuration \
    58	      "(AgentConfigurationWriteRequest (${agentSocketPath} ${agentMetaSocketPath} 384 ${agentDatabasePath} [(ProviderSeed (${providerName} ${providerEndpoint} ${defaultModel} (Gopass ${providerGopassPath})))] $out/${agentConfigurationPath}))" \
    59	      > "$out/configuration-written.nota"
    60	    test -s "$out/${agentConfigurationPath}"
    61	  '';
    62	
    63	  # The compatibility-named configuration field now carries only Spirit's
    64	  # typed judge socket and timeout. Provider/model selection belongs to the
    65	  # adapter service, not the Spirit daemon, so the legacy provider fields stay
    66	  # empty and cannot silently select a fallback judge.
    67	  guardianAgentConfiguration = "(Some (${spiritJudgeSocketPath} None None 180000 None))";
    68	
    69	  # AuthorizationMode gates the separate criome/mirror path. `Gating` remains
    70	  # Spirit's default; judge admission is independently mandatory through the
    71	  # configured typed judge socket.
    72	  authorizationMode = "Gating";
    73	
    74	  daemonConfiguration = pkgs.runCommand "spirit-daemon-configuration" { } ''
    75	    set -eu
    76	
    77	    mkdir -p "$out"
    78	    ${spiritPackage}/bin/spirit-write-configuration \
    79	      "(ConfigurationWriteRequest (${socketPath} (Some ${metaSocketPath}) ${databasePath} None ${authorizationMode} ${guardianAgentConfiguration} $out/${configurationPath}))" \
    80	      > "$out/configuration-written.nota"
    81	    test -s "$out/${configurationPath}"
    82	  '';
    83	
    84	  migrateState = ''
    85	    ${spiritPackage}/bin/spirit-migrate-store \
    86	      "($database_path)"
    87	  '';
    88	
    89	  activateState = pkgs.writeShellScript "spirit-activation-state" ''
    90	    set -eu
    91	
    92	    state_directory=${lib.escapeShellArg stateDirectory}
    93	    agent_state_directory=${lib.escapeShellArg agentStateDirectory}
    94	
    95	    ${pkgs.coreutils}/bin/mkdir -p "$state_directory"
    96	    ${pkgs.coreutils}/bin/mkdir -p "$agent_state_directory"
    97	  '';
    98	
    99	  initializeAgentState = pkgs.writeShellScript "agent-startup-state" ''
   100	    set -eu
   101	
   102	    agent_state_directory=${lib.escapeShellArg agentStateDirectory}
   103	
   104	    ${pkgs.coreutils}/bin/mkdir -p "$agent_state_directory"
   105	    ${pkgs.coreutils}/bin/rm -f \
   106	      ${lib.escapeShellArg agentSocketPath} \
   107	      ${lib.escapeShellArg agentMetaSocketPath}
   108	  '';
   109	
   110	  initializeState = pkgs.writeShellScript "spirit-startup-state" ''
   111	    set -eu
   112	
   113	    state_directory=${lib.escapeShellArg stateDirectory}
   114	    database_path=${lib.escapeShellArg databasePath}
   115	
   116	    ${pkgs.coreutils}/bin/mkdir -p "$state_directory"
   117	    ${pkgs.coreutils}/bin/rm -f \
   118	      ${lib.escapeShellArg socketPath} \
   119	      ${lib.escapeShellArg metaSocketPath}
   120	
   121	    ${migrateState}
   122	  '';
   123	
   124	  initializeJudgeState = pkgs.writeShellScript "spirit-judge-startup-state" ''
   125	    set -eu
   126	
   127	    ${pkgs.coreutils}/bin/mkdir -p ${lib.escapeShellArg stateDirectory}
   128	    ${pkgs.coreutils}/bin/rm -f ${lib.escapeShellArg spiritJudgeSocketPath}
   129	  '';
   130	
   131	  spiritJudgeServiceWrapper = pkgs.writeShellScriptBin "spirit-judge-daemon-service" ''
   132	    set -eu
   133	
   134	    # OpenAI Codex owns the authenticated session and receives no copied token.
   135	    # The reference is policy data only; the executable resolves it at runtime.
   136	    exec ${spiritJudgePackage}/bin/spirit-judge serve \
   137	      --socket ${lib.escapeShellArg spiritJudgeSocketPath} \
   138	      --config-root ${lib.escapeShellArg spiritJudgeConfig} \
   139	      --provider openai-codex \
   140	      --model gpt-5.6-terra \
   141	      --reasoning-effort medium \
   142	      --provider-timeout-milliseconds 180000 \
   143	      --external-authorization-source codex-login \
   144	      --session-launcher ${pkgs.util-linux}/bin/setsid \
   145	      --codex-command ${codexCliPackage}/bin/codex
   146	  '';
   147	
   148	  commandLineWrapper = pkgs.writeShellScriptBin "spirit" ''
   149	    export SPIRIT_SOCKET=${lib.escapeShellArg socketPath}
   150	    exec ${spiritPackage}/bin/spirit "$@"
   151	  '';
   152	
   153	  metaSpiritCommandLineWrapper = pkgs.writeShellScriptBin "meta-spirit" ''
   154	    export SPIRIT_META_SOCKET=${lib.escapeShellArg metaSocketPath}
   155	    exec ${spiritPackage}/bin/meta-spirit "$@"
   156	  '';
   157	
   158	  agentCommandLineWrapper = pkgs.writeShellScriptBin "agent" ''
   159	    export AGENT_SOCKET=${lib.escapeShellArg agentSocketPath}
   160	    exec ${agentPackage}/bin/agent "$@"
   161	  '';
   162	
   163	  agentServiceWrapper = pkgs.writeShellScriptBin "agent-daemon-service" ''
   164	    set -eu
   165	
   166	    exec ${agentPackage}/bin/agent-daemon ${agentDaemonConfiguration}/${agentConfigurationPath}
   167	  '';
   168	in
   169	{
   170	  options.criomosHome.spirit = {
   171	    enable = mkOption {
   172	      type = bool;
   173	      default = true;
   174	      description = "Deploy the schema-derived Spirit CLI and user-session daemon.";
   175	    };
   176	  };
   177	
   178	  config = mkIf (size.min && config.criomosHome.spirit.enable) {
   179	    home.packages = [
   180	      commandLineWrapper
   181	      metaSpiritCommandLineWrapper
   182	      agentCommandLineWrapper
   183	    ];
   184	
   185	    home.activation.spiritState = lib.hm.dag.entryAfter [ "writeBoundary" ] ''
   186	      $DRY_RUN_CMD ${activateState}
   187	    '';
   188	
   189	    systemd.user.services = {
   190	      spirit-judge = {
   191	        Unit = {
   192	          Description = "Spirit fail-closed judgment adapter";
   193	          StartLimitIntervalSec = 60;
   194	          StartLimitBurst = 5;
   195	        };
   196	
   197	        Service = {
   198	          ExecStartPre = "${initializeJudgeState}";
   199	          ExecStart = "${spiritJudgeServiceWrapper}/bin/spirit-judge-daemon-service";
   200	          Restart = "on-failure";
   201	          RestartSec = "2s";
   202	        };
   203	
   204	        Install.WantedBy = [ "default.target" ];
   205	      };
   206	
   207	      agent-daemon = {
   208	        Unit = {
   209	          Description = "Agent schema-derived daemon";
   210	          StartLimitIntervalSec = 60;
   211	          StartLimitBurst = 5;
   212	        };
   213	
   214	        Service = {
   215	          ExecStartPre = "${initializeAgentState}";
   216	          ExecStart = "${agentServiceWrapper}/bin/agent-daemon-service";
   217	          Environment = [ "PATH=${agentServicePath}" ];
   218	          Restart = "on-failure";
   219	          RestartSec = "2s";
   220	        };
   221	
   222	        Install.WantedBy = [ "default.target" ];
   223	      };
   224	    }
   225	    // {
   226	      spirit-daemon = {
   227	        Unit = {
   228	          Description = "Spirit schema-derived daemon";
   229	          Conflicts = [
   230	            "persona-spirit-daemon.service"
   231	            "persona-spirit-daemon-v0.1.0.service"
   232	            "persona-spirit-daemon-v0.1.1.service"
   233	            "persona-spirit-daemon-v0.2.0.service"
   234	            "persona-spirit-daemon-v0.3.0.service"
   235	            "persona-spirit-daemon-v0.4.0.service"
   236	            "persona-spirit-daemon-v0.4.1.service"
   237	            "persona-spirit-daemon-v0.4.2.service"
   238	            "persona-spirit-daemon-v0.5.0.service"
   239	            "persona-spirit-daemon-v0.5.1.service"
   240	            "persona-spirit-daemon-v0.5.2.service"
   241	            "persona-spirit-daemon-next.service"
   242	          ];
   243	          StartLimitIntervalSec = 60;
   244	          StartLimitBurst = 5;
   245	        }
   246	        // {
   247	          After = [ "spirit-judge.service" ];
   248	          Requires = [ "spirit-judge.service" ];
   249	        };
   250	
   251	        Service = {
   252	          ExecStartPre = "${initializeState}";
   253	          ExecStart = "${spiritPackage}/bin/spirit-daemon ${daemonConfiguration}/${configurationPath}";
   254	          Restart = "on-failure";
   255	          RestartSec = "2s";
   256	        };
   257	
   258	        Install.WantedBy = [ "default.target" ];
   259	      };
   260	    };
   261	  };
   262	}

content.text:
     1	{
     2	  pkgs,
     3	  ...
     4	}:
     5	let
     6	  lib = pkgs.lib;
     7	  system = pkgs.stdenv.hostPlatform.system;
     8	
     9	  fakeAgent = {
    10	    packages.${system}.default = pkgs.runCommand "fake-agent" { } ''
    11	      mkdir -p "$out/bin"
    12	      cat > "$out/bin/agent" <<'EOF'
    13	      #!${pkgs.runtimeShell}
    14	      printf 'socket=%s\n' "$AGENT_SOCKET"
    15	      EOF
    16	      cat > "$out/bin/agent-daemon" <<'EOF'
    17	      #!${pkgs.runtimeShell}
    18	      printf 'configuration=%s\n' "$1"
    19	      EOF
    20	      cat > "$out/bin/agent-write-configuration" <<'EOF'
    21	      #!${pkgs.runtimeShell}
    22	      set -eu
    23	      request=$1
    24	      case "$request" in
    25	        *'LOCAL_LLM_API_KEY'* | *'goldragon.criome/local-llm-api-token'*) exit 64 ;;
    26	        *'ProviderSeed (deepseek https://api.deepseek.com/v1 deepseek-v4-flash (Gopass platform.deepseek.com/api-key))'*) ;;
    27	        *) exit 65 ;;
    28	      esac
    29	      output_path=''${request##* }
    30	      output_path=''${output_path%))}
    31	      printf 'fake agent configuration archive\n' > "$output_path"
    32	      printf '(AgentConfigurationWritten %s)\n' "$output_path"
    33	      EOF
    34	      chmod +x "$out/bin/"*
    35	    '';
    36	  };
    37	
    38	  # This fake only renders and inspects Home's argv; it proves no real Codex
    39	  # executable, ambient login, or provider call. The pinned-package CLI contract
    40	  # is checked separately in checks/spirit-judge-cli-contract.
    41	  fakeCodex = {
    42	    packages.${system}.default = pkgs.writeShellScriptBin "codex" "exit 0";
    43	  };
    44	
    45	
    46	  fakeSpirit = {
    47	    packages.${system}.default = pkgs.runCommand "fake-spirit" { } ''
    48	      mkdir -p "$out/bin"
    49	      cat > "$out/bin/spirit" <<'EOF'
    50	      #!${pkgs.runtimeShell}
    51	      printf 'socket=%s\n' "$SPIRIT_SOCKET"
    52	      EOF
    53	      cat > "$out/bin/spirit-daemon" <<'EOF'
    54	      #!${pkgs.runtimeShell}
    55	      printf 'configuration=%s\n' "$1"
    56	      EOF
    57	      cat > "$out/bin/spirit-write-configuration" <<'EOF'
    58	      #!${pkgs.runtimeShell}
    59	      set -eu
    60	      request=$1
    61	      case "$request" in
    62	        *'['* | *']'*) exit 64 ;;
    63	        *'ConfigurationWriterGuardianAgent'*) exit 65 ;;
    64	        *'Some (/home/li/.local/state/spirit/spirit-judge.sock None None 180000 None)'*) ;;
    65	        *) exit 66 ;;
    66	      esac
    67	      output_path=''${request##* }
    68	      output_path=''${output_path%))}
    69	      printf 'fake configuration archive\n' > "$output_path"
    70	      printf '(ConfigurationWritten %s)\n' "$output_path"
    71	      EOF
    72	      cat > "$out/bin/spirit-migrate-store" <<'EOF'
    73	      #!${pkgs.runtimeShell}
    74	      set -eu
    75	      request=$1
    76	      case "$request" in
    77	        *'['* | *']'*) exit 64 ;;
    78	      esac
    79	      target_path=''${request#(}
    80	      target_path=''${target_path%)}
    81	      if [ -e "$target_path" ]; then
    82	        printf '(Current 1)\n'
    83	      else
    84	        printf '(Current 0)\n'
    85	      fi
    86	      EOF
    87	      chmod +x "$out/bin/"*
    88	    '';
    89	  };
    90	
    91	  fakeSpiritJudge = {
    92	    packages.${system}.default = pkgs.runCommand "fake-spirit-judge" { } ''
    93	      mkdir -p "$out/bin"
    94	      cat > "$out/bin/spirit-judge" <<'EOF'
    95	      #!${pkgs.runtimeShell}
    96	      printf 'judge=%s\n' "$*"
    97	      EOF
    98	      chmod +x "$out/bin/spirit-judge"
    99	    '';
   100	  };
   101	
   102	  fakeSpiritJudgeConfig = pkgs.runCommand "fake-spirit-judge-config" { } ''
   103	    mkdir -p "$out/prompts"
   104	  '';
   105	
   106	  moduleResult = import ../../modules/home/profiles/min/spirit.nix {
   107	    inherit pkgs;
   108	    lib = lib // {
   109	      hm.dag.entryAfter = _after: data: { inherit data; };
   110	      hm.dag.entryBetween = _before: _after: data: { inherit data; };
   111	    };
   112	    inputs = {
   113	      agent = fakeAgent;
   114	      codex-cli = fakeCodex;
   115	      criomos-lib = ../../stubs/criomos-lib;
   116	      spirit = fakeSpirit;
   117	      spirit-judge = fakeSpiritJudge;
   118	      spirit-judge-config = fakeSpiritJudgeConfig;
   119	    };
   120	    config = {
   121	      home.homeDirectory = "/home/li";
   122	      criomosHome.spirit.enable = true;
   123	    };
   124	    horizon = {
   125	      node = {
   126	        typeIs.largeAiRouter = false;
   127	        behavesAs.largeAi = true;
   128	        criomeDomainName = "prometheus.goldragon.criome";
   129	      };
   130	    };
   131	    user.size.min = true;
   132	  };
   133	
   134	  moduleConfiguration =
   135	    if moduleResult.config ? content then moduleResult.config.content else moduleResult.config;
   136	
   137	  services = moduleConfiguration.systemd.user.services;
   138	  homePackages = moduleConfiguration.home.packages;
   139	  activation = moduleConfiguration.home.activation.spiritState.data;
   140	  profileWitness = pkgs.symlinkJoin {
   141	    name = "spirit-profile-witness";
   142	    paths = homePackages;
   143	  };
   144	
   145	  assertions = [
   146	    {
   147	      condition = builtins.hasAttr "agent-daemon" services;
   148	      message = "the schema-derived agent daemon service must exist.";
   149	    }
   150	    {
   151	      condition = builtins.hasAttr "spirit-judge" services;
   152	      message = "the persistent Spirit judge service must exist.";
   153	    }
   154	    {
   155	      condition = builtins.hasAttr "spirit-daemon" services;
   156	      message = "the schema-derived spirit daemon service must exist.";
   157	    }
   158	    {
   159	      condition = builtins.hasAttr "spirit-judge" services;
   160	      message = "the fail-closed Spirit judge service must exist.";
   161	    }
   162	    {
   163	      condition = builtins.elem "spirit-judge.service" services.spirit-daemon.Unit.Requires;
   164	      message = "the Spirit daemon must require the judgment adapter service.";
   165	    }
   166	    {
   167	      condition = !(builtins.hasAttr "persona-spirit-daemon" services);
   168	      message = "the unversioned persona-spirit daemon service must be absent.";
   169	    }
   170	    {
   171	      condition = !(builtins.hasAttr "persona-spirit-daemon-v0.5.2" services);
   172	      message = "the old persona-spirit v0.5.2 daemon service must be absent.";
   173	    }
   174	  ];
   175	
   176	  failures = builtins.filter (assertion: !assertion.condition) assertions;
   177	in
   178	if failures != [ ] then
   179	  throw (lib.concatMapStringsSep "\n" (assertion: assertion.message) failures)
   180	else
   181	  pkgs.runCommand "spirit-deployment" { } ''
   182	    set -eu
   183	
   184	    test -x "${profileWitness}/bin/spirit"
   185	    test -x "${profileWitness}/bin/agent"
   186	    ! test -e "${profileWitness}/bin/spirit-v0.5.2"
   187	    ! test -e "${profileWitness}/bin/spirit-next"
   188	
   189	    SPIRIT_SOCKET=/stale/socket "${profileWitness}/bin/spirit" > current
   190	    grep -q '^socket=/home/li/.local/state/spirit/spirit.sock$' current
   191	    AGENT_SOCKET=/stale/socket "${profileWitness}/bin/agent" > current-agent
   192	    grep -q '^socket=/home/li/.local/state/agent/agent.sock$' current-agent
   193	
   194	    agent_exec_start="${services.agent-daemon.Service.ExecStart}"
   195	    agent_exec_start_pre="${services.agent-daemon.Service.ExecStartPre}"
   196	    judge_exec_start="${services.spirit-judge.Service.ExecStart}"
   197	    judge_exec_start_pre="${services.spirit-judge.Service.ExecStartPre}"
   198	    exec_start="${services.spirit-daemon.Service.ExecStart}"
   199	    exec_start_pre="${services.spirit-daemon.Service.ExecStartPre}"
   200	    activation_script="${pkgs.writeText "activation" activation}"
   201	
   202	    printf '%s\n' "$agent_exec_start" > agent-exec-start
   203	    printf '%s\n' "$agent_exec_start_pre" > agent-exec-start-pre
   204	    printf '%s\n' "$judge_exec_start" > judge-exec-start
   205	    printf '%s\n' "$judge_exec_start_pre" > judge-exec-start-pre
   206	    printf '%s\n' "$exec_start" > exec-start
   207	    printf '%s\n' "$exec_start_pre" > exec-start-pre
   208	    cat "$activation_script" > activation
   209	
   210	    grep -q '/bin/agent-daemon-service$' agent-exec-start
   211	    ! grep -q 'agent-write-configuration' agent-exec-start
   212	    cat "$agent_exec_start" > agent-daemon-service
   213	    grep -q '/bin/agent-daemon ' agent-daemon-service
   214	    grep -q '/agent.config.rkyv$' agent-daemon-service
   215	    ! grep -q 'gopass show' agent-daemon-service
   216	    ! grep -q 'LOCAL_LLM_API_KEY' agent-daemon-service
   217	    agent_configuration_archive="$(${pkgs.gnused}/bin/sed -n 's|.*agent-daemon \([^ ]*agent.config.rkyv\).*|\1|p' agent-daemon-service)"
   218	    test -n "$agent_configuration_archive"
   219	    test -s "$agent_configuration_archive"
   220	    grep -q 'mkdir -p' "$agent_exec_start_pre"
   221	    grep -q '/agent/agent.sock' "$agent_exec_start_pre"
   222	
   223	    grep -q '/bin/spirit-judge-daemon-service$' judge-exec-start
   224	    cat "$judge_exec_start" > spirit-judge-daemon-service
   225	    cat "$judge_exec_start_pre" > spirit-judge-startup-state
   226	    grep -q '/spirit-judge.sock' spirit-judge-startup-state
   227	
   228	    cat "$judge_exec_start" > spirit-judge-daemon-service
   229	    grep -q -- '--provider openai-codex' spirit-judge-daemon-service
   230	    grep -q -- '--model gpt-5.6-terra' spirit-judge-daemon-service
   231	    grep -q -- '--reasoning-effort medium' spirit-judge-daemon-service
   232	    grep -q -- '--provider-timeout-milliseconds 180000' spirit-judge-daemon-service
   233	    grep -q -- '--external-authorization-source codex-login' spirit-judge-daemon-service
   234	    grep -q -- '--session-launcher ' spirit-judge-daemon-service
   235	    grep -q -- '--codex-command ' spirit-judge-daemon-service
   236	    ! grep -q 'gopass show' spirit-judge-daemon-service
   237	    ! grep -q 'bearer-secret-source' spirit-judge-daemon-service
   238	    ! grep -q 'deepseek-v4-pro' spirit-judge-daemon-service
   239	
   240	    grep -q '/bin/spirit-daemon ' exec-start
   241	    grep -q '/spirit.config.rkyv$' exec-start
   242	    ! grep -q 'spirit-write-configuration' exec-start
   243	    ! grep -q 'persona-spirit' exec-start
   244	
   245	    test -s "$(printf '%s\n' "$exec_start" | ${pkgs.gnused}/bin/sed 's|.* ||')"
   246	    grep -q 'spirit-migrate-store' "$exec_start_pre"
   247	    ! grep -q 'spirit-migrate-production' "$exec_start_pre"
   248	    ! grep -q 'spirit-upgrade-store' "$exec_start_pre"
   249	    grep -q '(\$database_path)' "$exec_start_pre"
   250	    grep -q '/spirit/spirit.sema' "$exec_start_pre"
   251	
   252	    grep -q 'spirit-activation-state' activation
   253	    ! grep -q 'spirit-startup-state' activation
   254	    activation_state="$(sed -n 's|.*\(/nix/store/[^ ]*-spirit-activation-state\).*|\1|p' activation)"
   255	    test -n "$activation_state"
   256	    grep -q 'mkdir -p' "$activation_state"
   257	    grep -q '/agent' "$activation_state"
   258	    ! grep -q 'spirit-migrate-store' "$activation_state"
   259	    ! grep -q 'spirit-migrate-production' "$activation_state"
   260	    ! grep -q 'spirit-upgrade-store' "$activation_state"
   261	    ! grep -q 'rm -f' "$activation_state"
   262	
   263	    touch "$out"
   264	  ''

MODULE
     1	{
     2	  config,
     3	  inputs,
     4	  lib,
     5	  pkgs,
     6	  horizon,
     7	  user,
