   326	impl ProviderSecretResolver for EnvironmentSecretResolver {
   327	    fn resolve(&self, reference: &SecretSourceReference) -> Result<TransientBearerSecret, Error> {
   328	        let Some(name) = reference.as_str().strip_prefix("env:") else {
   329	            return Err(Error::SecretSourceUnsupported(
   330	                reference.as_str().to_owned(),
   331	            ));
   332	        };
   333	        if name.is_empty() {
   334	            return Err(Error::EmptyValue);
   335	        }
   336	        std::env::var(name)
   337	            .map_err(|_| Error::SecretSourceUnavailable(reference.as_str().to_owned()))
   338	            .and_then(TransientBearerSecret::new)
   339	    }
   340	}
