   489	
   490	#[derive(Clone, Debug, PartialEq, Eq)]
   491	pub struct OpenAiCodexProviderClient {
   492	    session_launcher: PathBuf,
   493	    command: PathBuf,
   494	    timeout: ProviderCallTimeout,
   495	}
   496	
   497	impl OpenAiCodexProviderClient {
   498	    pub fn new(
   499	        session_launcher: impl Into<PathBuf>,
   500	        command: impl Into<PathBuf>,
   501	        timeout: ProviderCallTimeout,
   502	    ) -> Self {
   503	        Self {
   504	            session_launcher: session_launcher.into(),
   505	            command: command.into(),
   506	            timeout,
   507	        }
   508	    }
   509	
   510	    fn verify_authorization(
   511	        &self,
   512	        authorization: &ResolvedProviderAuthorization,
   513	    ) -> Result<(), Error> {
   514	        let ResolvedProviderAuthorization::ExternalSession(reference) = authorization else {
   515	            return Err(Error::ProviderAuthorizationUnsupported);
   516	        };
   517	        if reference.as_str() != CODEX_AMBIENT_SESSION_REFERENCE {
   518	            return Err(Error::ProviderAuthorizationReferenceUnsupported);
   519	        }
   520	        let output = CodexChildProcess::new(
   521	            &self.session_launcher,
   522	            &self.command,
   523	            vec![OsString::from("login"), OsString::from("status")],
   524	            self.timeout,
   525	        )
   526	        .execute()?;
   527	        if !output.status.success() {
   528	            return Err(Error::ProviderAuthorizationUnsupported);
   529	        }
   530	        Ok(())
   531	    }
   532	}
