   534	impl ProviderClient for OpenAiCodexProviderClient {
   535	    fn call(&self, request: ProviderCallRequest) -> Result<ProviderCallReply, Error> {
   536	        if self.command.is_absolute() && !self.command.is_file() {
   537	            return Err(Error::ProviderCommandUnavailable);
   538	        }
   539	        self.verify_authorization(request.authorization())?;
   540	        OpenAiCodexInvocation::from_request(
   541	            &self.session_launcher,
   542	            &self.command,
   543	            self.timeout,
   544	            request,
   545	        )?
   546	        .execute()
   547	    }
   548	}
