   222	    pub fn admission_user_text(&self, packet: &AdmissionJudgePacket) -> String {
   223	        self.user_template
   224	            .replace("{operation}", packet.operation.name())
   225	            .replace("{candidate}", &packet.operation.to_nota())
   226	            .replace("{bundle}", &packet.records.to_nota())
   227	            .replace("{retry_instruction}", "")
   228	    }
