   285	    pub fn judge(&self, request: SpiritJudgeRequest) -> SpiritJudgeReply {
   286	        match request {
   287	            SpiritJudgeRequest::JudgeAdmission(packet) => self.judge_admission(packet),
   288	            SpiritJudgeRequest::JudgeReferentRegistration(packet) => {
   289	                self.judge_referent_registration(packet)
   290	            }
   291	        }
   292	    }
