   294	    fn judge_admission(&self, packet: AdmissionJudgePacket) -> SpiritJudgeReply {
   295	        let diagnostic_scope = DiagnosticScope::new(&packet.scope);
   296	        let prompt = match PromptPack::read_admission(self.configuration.configuration_path()) {
   297	            Ok(prompt) => prompt,
   298	            Err(error) => {
   299	                return SpiritJudgeReply::RequestRejected(SpiritJudgeRequestRejection::new(
   300	                    SpiritJudgeRequestRejectionReason::ConfigurationUnavailable,
   301	                    diagnostic_scope.failure("configuration unavailable", Some(error.to_string())),
   302	                ));
   303	            }
   304	        };
   305	        let request = self.admission_provider_request(&prompt, &packet);
   306	        let reply = match self.provider_client.call(request) {
   307	            Ok(reply) => reply,
   308	            Err(error) => {
   309	                return SpiritJudgeReply::RequestRejected(SpiritJudgeRequestRejection::new(
   310	                    SpiritJudgeRequestRejectionReason::ProviderUnavailable,
   311	                    diagnostic_scope.failure("provider unavailable", Some(error.to_string())),
   312	                ));
   313	            }
   314	        };
   315	        self.admission_reply_from_provider(reply, diagnostic_scope)
   316	    }
   317	
   318	    fn judge_referent_registration(
   319	        &self,
   320	        packet: ReferentRegistrationJudgePacket,
   321	    ) -> SpiritJudgeReply {
   322	        let diagnostic_scope = DiagnosticScope::new(&packet.scope);
   323	        let prompt =
   324	            match PromptPack::read_referent_registration(self.configuration.configuration_path()) {
   325	                Ok(prompt) => prompt,
   326	                Err(error) => {
   327	                    return SpiritJudgeReply::RequestRejected(SpiritJudgeRequestRejection::new(
   328	                        SpiritJudgeRequestRejectionReason::ConfigurationUnavailable,
   329	                        diagnostic_scope
   330	                            .failure("configuration unavailable", Some(error.to_string())),
   331	                    ));
   332	                }
   333	            };
   334	        let request = self.referent_registration_provider_request(&prompt, &packet);
   335	        let reply = match self.provider_client.call(request) {
   336	            Ok(reply) => reply,
   337	            Err(error) => {
   338	                return SpiritJudgeReply::RequestRejected(SpiritJudgeRequestRejection::new(
   339	                    SpiritJudgeRequestRejectionReason::ProviderUnavailable,
   340	                    diagnostic_scope.failure("provider unavailable", Some(error.to_string())),
   341	                ));
   342	            }
   343	        };
   344	        self.referent_registration_reply_from_provider(reply, diagnostic_scope)
   345	    }
