   388	    fn admission_reply_from_provider(
   389	        &self,
   390	        reply: ProviderCallReply,
   391	        diagnostic_scope: DiagnosticScope<'_>,
   392	    ) -> SpiritJudgeReply {
   393	        if let Ok(response) = NotaSource::new(reply.output_text()).parse::<AdmissionJudgeResponse>()
   394	        {
   395	            return SpiritJudgeReply::AdmissionJudged(response);
   396	        }
   397	        match NotaSource::new(reply.output_text()).parse::<ModelAdmissionVerdict>() {
   398	            Ok(verdict) => {
   399	                SpiritJudgeReply::AdmissionJudged(verdict.into_response(&diagnostic_scope))
   400	            }
   401	            Err(error) => SpiritJudgeReply::RequestRejected(SpiritJudgeRequestRejection::new(
   402	                SpiritJudgeRequestRejectionReason::ResponseFormatFailure,
   403	                diagnostic_scope.failure(
   404	                    "model response did not match Spirit admission judge NOTA shape",
   405	                    Some(format!(
   406	                        "{error}; {}",
   407	                        ContentHasher::new(reply.output_text()).hash().as_str()
   408	                    )),
   409	                ),
   410	            )),
   411	        }
   412	    }
