   734	struct RequestEnvelope {
   735	    exchange: ExchangeIdentifier,
   736	    request: signal_frame::Request<SpiritJudgeRequest>,
   737	}
   738	
   739	impl RequestEnvelope {
   740	    fn from_frame(frame: SpiritJudgeFrame) -> Result<Self, Error> {
   741	        match frame.into_body() {
   742	            ExchangeFrameBody::Request { exchange, request } => Ok(Self { exchange, request }),
   743	            ExchangeFrameBody::HandshakeRequest(_) => {
   744	                Err(Error::UnexpectedFrame("handshake request"))
   745	            }
   746	            ExchangeFrameBody::HandshakeReply(_) => Err(Error::UnexpectedFrame("handshake reply")),
