   752	struct FrameTransport;
   753	
   754	impl FrameTransport {
   755	    async fn read_frame(stream: &mut UnixStream) -> Result<SpiritJudgeFrame, Error> {
   756	        let bytes = Self::read_length_prefixed_bytes(stream).await?;
   757	        SpiritJudgeFrame::decode_length_prefixed(bytes.as_slice())
   758	            .map_err(|error| Error::Frame(error.to_string()))
   759	    }
   760	
   761	    async fn write_frame(stream: &mut UnixStream, frame: &SpiritJudgeFrame) -> Result<(), Error> {
   762	        let bytes = frame
   763	            .encode_length_prefixed()
   764	            .map_err(|error| Error::Frame(error.to_string()))?;
   765	        stream
   766	            .write_all(bytes.as_slice())
   767	            .await
   768	            .map_err(Error::Socket)?;
   769	        stream.flush().await.map_err(Error::Socket)?;
   770	        Ok(())
   771	    }
   772	
   773	    async fn read_length_prefixed_bytes(stream: &mut UnixStream) -> Result<Vec<u8>, Error> {
   774	        let mut prefix = [0_u8; 4];
   775	        stream
   776	            .read_exact(&mut prefix)
   777	            .await
   778	            .map_err(Error::Socket)?;
   779	        let length = u32::from_be_bytes(prefix) as usize;
   780	        let mut bytes = Vec::with_capacity(4 + length);
   781	        bytes.extend_from_slice(&prefix);
   782	        bytes.resize(4 + length, 0);
   783	        stream
   784	            .read_exact(&mut bytes[4..])
   785	            .await
   786	            .map_err(Error::Socket)?;
   787	        Ok(bytes)
   788	    }
   789	}
