   832	    }
   833	
   834	    fn reply_from_frame(frame: SpiritJudgeFrame) -> Result<SpiritJudgeReply, Error> {
   835	        match frame.into_body() {
   836	            ExchangeFrameBody::Reply { reply, .. } => match reply {
   837	                Reply::Accepted { per_operation, .. } => {
   838	                    Ok(per_operation.into_head().representative_reply())
   839	                }
   840	                Reply::Rejected { reason } => Err(Error::Frame(reason.to_string())),
   841	            },
   842	            ExchangeFrameBody::HandshakeRequest(_) => {
   843	                Err(Error::UnexpectedFrame("handshake request"))
   844	            }
   845	            ExchangeFrameBody::HandshakeReply(_) => Err(Error::UnexpectedFrame("handshake reply")),
   846	            ExchangeFrameBody::Request { .. } => Err(Error::UnexpectedFrame("request")),
   847	        }
   848	    }
   849	}
