   174	impl PromptPack {
   175	    pub fn read_admission(
   176	        configuration_path: &SpiritJudgeConfigurationPath,
   177	    ) -> Result<Self, Error> {
   178	        let sections = ADMISSION_PROMPT_PATHS
   179	            .iter()
   180	            .map(|path| PromptFile::new(path).read_from(configuration_path))
   181	            .collect::<Result<Vec<_>, _>>()?;
   182	        Ok(Self {
   183	            system_text: sections.join("\n\n"),
   184	            user_template: PromptFile::new(ADMISSION_USER_TEMPLATE_PATH)
   185	                .read_from(configuration_path)?,
   186	        })
   187	    }
