   189	    pub fn read_referent_registration(
   190	        configuration_path: &SpiritJudgeConfigurationPath,
   191	    ) -> Result<Self, Error> {
   192	        let system = PromptFile::new(REFERENT_SYSTEM_PROMPT_PATH)
   193	            .read_from(configuration_path)?
   194	            .replace(
   195	                "{accept}",
   196	                &ModelReferentRegistrationVerdict::Accept.to_nota(),
   197	            )
   198	            .replace(
   199	                "{reject}",
   200	                &ModelReferentRegistrationVerdict::RejectReferent(
   201	                    ModelReferentRegistrationRejection::new(
   202	                        ReferentRegistrationRejectionReason::NonReferent,
   203	                        RedactedText::new("a verb or concept is not a nameable particular")
   204	                            .expect("static diagnostic is non-empty"),
   205	                    ),
   206	                )
   207	                .to_nota(),
   208	            );
   209	        let retry = PromptFile::new(RETRY_INSTRUCTION_PATH).read_from(configuration_path)?;
   210	        let diagnostics = PromptFile::new(DIAGNOSTICS_PROMPT_PATH).read_from(configuration_path)?;
   211	        Ok(Self {
   212	            system_text: [system, retry, diagnostics].join("\n\n"),
   213	            user_template: PromptFile::new(REFERENT_USER_TEMPLATE_PATH)
   214	                .read_from(configuration_path)?,
   215	        })
   216	    }
