   606	pub struct SpiritJudgeSocketServer<Client> {
   607	    socket_path: SpiritJudgeSocketPath,
   608	    adapter: SpiritJudgeAdapter<Client>,
   609	}
   610	
   611	impl<Client> SpiritJudgeSocketServer<Client>
   612	where
   613	    Client: ProviderClient,
   614	{
   615	    pub fn new(socket_path: SpiritJudgeSocketPath, adapter: SpiritJudgeAdapter<Client>) -> Self {
   616	        Self {
   617	            socket_path,
   618	            adapter,
   619	        }
   620	    }
   621	
   622	    pub async fn serve_one(self) -> Result<SpiritJudgeReply, Error> {
   623	        self.socket_path.remove_stale()?;
   624	        let listener = UnixListener::bind(self.socket_path.as_path()).map_err(Error::Socket)?;
   625	        let result = async {
   626	            let (mut stream, _) = listener.accept().await.map_err(Error::Socket)?;
   627	            self.serve_stream(&mut stream).await
   628	        }
   629	        .await;
   630	        self.socket_path.remove_stale()?;
   631	        result
   632	    }
   633	
   634	    /// Serve direct-bind connections until the process is stopped.
   635	    ///
   636	    /// Production Spirit depends on this listener remaining available between
   637	    /// submissions. A missing or failed listener is intentionally fail-closed
   638	    /// at Spirit's client boundary, but an idle period is not a failure and
   639	    /// must not tear down the judge socket.
   640	    pub async fn serve(self) -> Result<(), Error> {
   641	        self.socket_path.remove_stale()?;
   642	        let listener = UnixListener::bind(self.socket_path.as_path()).map_err(Error::Socket)?;
   643	        let result = async {
   644	            loop {
   645	                let (mut stream, _) = listener.accept().await.map_err(Error::Socket)?;
   646	                self.serve_stream(&mut stream).await?;
   647	            }
   648	        }
   649	        .await;
   650	        self.socket_path.remove_stale()?;
   651	        result
   652	    }
   653	
   654	    /// Serve sequential direct-bind connections until no client arrives within
   655	    /// `idle_timeout`. This bounded form is retained for isolated tests and
   656	    /// short-lived diagnostic probes; production uses [`Self::serve`].
   657	    pub async fn serve_until_idle(self, idle_timeout: Duration) -> Result<usize, Error> {
   658	        self.socket_path.remove_stale()?;
   659	        let listener = UnixListener::bind(self.socket_path.as_path()).map_err(Error::Socket)?;
   660	        let mut served = 0;
   661	        let result = async {
   662	            loop {
   663	                let accepted = timeout(idle_timeout, listener.accept()).await;
   664	                let (mut stream, _) = match accepted {
   665	                    Ok(Ok(accepted)) => accepted,
   666	                    Ok(Err(error)) => return Err(Error::Socket(error)),
   667	                    Err(_elapsed) => return Ok(served),
   668	                };
   669	                self.serve_stream(&mut stream).await?;
   670	                served += 1;
   671	            }
   672	        }
   673	        .await;
   674	        self.socket_path.remove_stale()?;
   675	        result
   676	    }
   677	
   678	    pub async fn serve_stream(&self, stream: &mut UnixStream) -> Result<SpiritJudgeReply, Error> {
   679	        let frame = FrameTransport::read_frame(stream).await?;
   680	        let envelope = RequestEnvelope::from_frame(frame)?;
   681	        let replies = envelope
   682	            .request
   683	            .payloads()
   684	            .iter()
   685	            .cloned()
   686	            .map(|payload| SubReply::Ok(self.adapter.judge(payload)))
   687	            .collect::<Vec<_>>();
   688	        let reply_payloads =
   689	            NonEmpty::try_from_vec(replies).map_err(|error| Error::Frame(error.to_string()))?;
   690	        let representative = reply_payloads.head().representative_reply();
   691	        let frame = SpiritJudgeFrame::with_short_header(
   692	            ShortHeader::empty(),
   693	            ExchangeFrameBody::Reply {
   694	                exchange: envelope.exchange,
   695	                reply: Reply::committed(reply_payloads),
   696	            },
   697	        );
   698	        FrameTransport::write_frame(stream, &frame).await?;
   699	        Ok(representative)
   700	    }
   701	}
