   801	        let mut stream = UnixStream::connect(self.socket_path.as_path())
   802	            .await
   803	            .map_err(Error::Socket)?;
   804	        let exchange = ClientExchange::first().identifier();
   805	        let request = Request::from_payload(request);
   806	        let frame = SpiritJudgeFrame::with_short_header(
