   808	            ExchangeFrameBody::Request { exchange, request },
   809	        );
   810	        FrameTransport::write_frame(&mut stream, &frame).await?;
   811	        let frame = FrameTransport::read_frame(&mut stream).await?;
   812	        ClientExchange::reply_from_frame(frame)
